const MANIFEST: string = "{\n  \"name\": \"NexPlay\",\n  \"short_name\": \"NexPlay\",\n  \"description\": \"Stream movies, series and live TV channels. Free, no sign-up.\",\n  \"start_url\": \"/\",\n  \"display\": \"standalone\",\n  \"background_color\": \"#0d1117\",\n  \"theme_color\": \"#7c3aed\",\n  \"orientation\": \"portrait-primary\",\n  \"icons\": [\n    {\n      \"src\": \"/icon.png\",\n      \"sizes\": \"192x192\",\n      \"type\": \"image/png\",\n      \"purpose\": \"any maskable\"\n    },\n    {\n      \"src\": \"/icon.png\",\n      \"sizes\": \"512x512\",\n      \"type\": \"image/png\",\n      \"purpose\": \"any maskable\"\n    }\n  ]\n}";
const SW: string       = "\nconst CACHE = 'nexplay-v20614';\nself.addEventListener('install', e => {\n  // Pre-cache shell for offline fallback\n  e.waitUntil(caches.open(CACHE).then(c => c.add('/')));\n  self.skipWaiting();\n});\nself.addEventListener('activate', e => {\n  // Delete ALL old caches so stale builds never come back\n  e.waitUntil(caches.keys().then(ks =>\n    Promise.all(ks.filter(k => k !== CACHE).map(k => caches.delete(k)))\n  ));\n  self.clients.claim();\n});\nself.addEventListener('fetch', e => {\n  if (e.request.method !== 'GET') return;\n  const url = new URL(e.request.url);\n  // Network-first for the shell so every deploy reaches clients immediately.\n  // Falls back to cache only when offline.\n  if (url.pathname === '/') {\n    e.respondWith(\n      fetch(e.request).then(res => {\n        const clone = res.clone();\n        caches.open(CACHE).then(c => c.put(e.request, clone));\n        return res;\n      }).catch(() => caches.match(e.request))\n    );\n  }\n});\n";
const ICON_B64: string = "";

function b64ToUint8(b64: string): Uint8Array {
  const bin = atob(b64);
  const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  return arr;
}

function detectClient(ua: string): string {
  if (!ua) return "unknown";
  const has = (p: RegExp) => p.test(ua);
  const ver = (p: RegExp) => { const m = ua.match(p); return m ? m[1] : ""; };

  const device =
    has(/Tizen|SmartTV|SMART-TV/i) ? "Samsung-TV" :
    has(/iPhone/i)   ? "iPhone" :
    has(/iPad/i)     ? "iPad" :
    has(/Android/i)  ? (ua.includes("Mobile") ? "Android-Phone" : "Android-Tablet") :
    has(/Windows/i)  ? "Windows" :
    has(/Mac OS/i)   ? "Mac" :
    has(/Linux/i)    ? "Linux" : "Other";

  const browser =
    has(/EdgA?\//i)         ? "Edge/"    + ver(/EdgA?\/(\d+)/i) :
    has(/OPR\//i)           ? "Opera/"   + ver(/OPR\/(\d+)/i) :
    has(/SamsungBrowser/i)   ? "Samsung/" + ver(/SamsungBrowser\/(\d+)/i) :
    has(/Firefox\//i)       ? "Firefox/" + ver(/Firefox\/(\d+)/i) :
    has(/Chrome\//i)        ? "Chrome/"  + ver(/Chrome\/(\d+)/i) :
    has(/Version\/.*Safari/i) ? "Safari/" + ver(/Version\/(\d+)/i) :
    has(/Safari\//i)        ? "Safari/?" : "?";

  return device + "/" + browser;
}

function log(req: Request, status: number, ms: number, label: string): void {
  const url   = new URL(req.url);
  const ua    = req.headers.get("user-agent") || "";
  const ip    = req.headers.get("x-forwarded-for")?.split(",")[0].trim()
             || req.headers.get("cf-connecting-ip")
             || "—";
  const lang  = req.headers.get("accept-language")?.split(",")[0] || "—";
  const ref   = req.headers.get("referer") || "—";
  const client = detectClient(ua);
  const ts    = new Date().toISOString();

  console.log(
    `[${ts}] ${req.method} ${url.pathname} ${status} ${ms}ms` +
    ` | client=${client} ip=${ip} lang=${lang}` +
    (url.pathname === "/" ? ` referer=${ref}` : "") +
    (label ? ` [${label}]` : "")
  );
}

Deno.serve((req: Request): Response => {
  const t0  = Date.now();
  const url = new URL(req.url);

  let res: Response;
  let label = "";

  if (url.pathname === "/manifest.json") {
    label = "PWA-manifest";
    res = new Response(MANIFEST, {
      headers: { "Content-Type": "application/manifest+json", "Cache-Control": "public, max-age=86400" },
    });
  } else if (url.pathname === "/sw.js") {
    label = "PWA-sw";
    res = new Response(SW, {
      headers: { "Content-Type": "application/javascript", "Cache-Control": "no-cache" },
    });
  } else if (url.pathname === "/icon.png" && ICON_B64) {
    label = "icon";
    res = new Response(b64ToUint8(ICON_B64), {
      headers: { "Content-Type": "image/png", "Cache-Control": "public, max-age=31536000" },
    });
  } else {
    res = new Response(HTML, {
      headers: {
        "Content-Type":           "text/html; charset=utf-8",
        "Cache-Control":          "no-cache, no-store, must-revalidate",
        "X-Content-Type-Options": "nosniff",
        "Referrer-Policy":        "no-referrer-when-downgrade",
      },
    });
  }

  log(req, res.status, Date.now() - t0, label);
  return res;
});
